import{_ as a,o as i,c as s,a6 as t}from"./chunks/framework.CgU7tkAh.js";const k=JSON.parse('{"title":"Getting started","description":"","frontmatter":{},"headers":[],"relativePath":"guide/get-started.md","filePath":"guide/get-started.md"}'),n={name:"guide/get-started.md"};function l(o,e,r,d,p,h){return i(),s("div",null,[...e[0]||(e[0]=[t(`<h1 id="getting-started" tabindex="-1">Getting started <a class="header-anchor" href="#getting-started" aria-label="Permalink to “Getting started”">​</a></h1><p>Section briefly describes how to configure, build and start the Intake24 components for development and production deployment.</p><h2 id="prerequisites" tabindex="-1">Prerequisites <a class="header-anchor" href="#prerequisites" aria-label="Permalink to “Prerequisites”">​</a></h2><ul><li><code>Git</code></li><li><code>Node.js</code> - latest LTS</li><li><code>pnpm</code> package manager</li><li>4vGB+ free disk space (Or 50GB+ free disk space including downloading and extracting food images and database snapshots)</li><li><code>PostgreSQL</code> and <code>Redis</code> instances</li></ul><p>Options to set up local <code>PostgreSQL</code> and <code>Redis</code> instances:</p><h4 id="method-1-docker-compose" tabindex="-1">Method 1: Docker compose <a class="header-anchor" href="#method-1-docker-compose" aria-label="Permalink to “Method 1: Docker compose”">​</a></h4><p>Execute Docker compose file <code>docker-compose.yml</code> to prepare PostgresQL and Redis instances, and map out port 5432 and 6379 respectively by default. More details can be found in <a href="/guide/docker">Development using Docker</a>.</p><h4 id="method-2-virtual-machine" tabindex="-1">Method 2: Virtual Machine <a class="header-anchor" href="#method-2-virtual-machine" aria-label="Permalink to “Method 2: Virtual Machine”">​</a></h4><p>Run Dev VM (download from S3 bucket - contact the Intake24 team), which maps out the database on 192.168.56.10:5432 (PostgreSQL). More details can be found in <a href="/guide/vm">Development using VM</a>.</p><h4 id="method-3-manual-installation" tabindex="-1">Method 3: Manual installation <a class="header-anchor" href="#method-3-manual-installation" aria-label="Permalink to “Method 3: Manual installation”">​</a></h4><p>Install <code>PostgreSQL</code> and <code>Redis</code> manually on your local machine. Refer to the official documentation for <a href="https://www.postgresql.org/docs/current" target="_blank" rel="noreferrer">PostgreSQL</a> and <a href="https://redis.io/docs" target="_blank" rel="noreferrer">Redis</a> for installation instructions.</p><h2 id="development" tabindex="-1">Development <a class="header-anchor" href="#development" aria-label="Permalink to “Development”">​</a></h2><h4 id="_1-clone-repository" tabindex="-1">1. Clone repository <a class="header-anchor" href="#_1-clone-repository" aria-label="Permalink to “1. Clone repository”">​</a></h4><div class="language-sh"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> clone</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://github.com/intake24/intake24</span></span></code></pre></div><p>More details can be found in <a href="/guide/source-code">Source code</a> for detailed instructions about repository structure.</p><h4 id="_2-install-pnpm-using-corepack" tabindex="-1">2. Install pnpm using corepack <a class="header-anchor" href="#_2-install-pnpm-using-corepack" aria-label="Permalink to “2. Install pnpm using corepack”">​</a></h4><div class="language-sh"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">corepack</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> enable</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">corepack</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span></span></code></pre></div><p>More details can be found in <a href="/guide/source-code#dependencies">Source code -&gt; Dependencies</a>.</p><h4 id="_3-install-dependencies" tabindex="-1">3. Install dependencies <a class="header-anchor" href="#_3-install-dependencies" aria-label="Permalink to “3. Install dependencies”">​</a></h4><p>On project root folder, run</p><div class="language-sh"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">pnpm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span></span></code></pre></div><h4 id="_4-spin-up-redis-and-postgresql-instance" tabindex="-1">4. Spin up Redis and PostgreSQL instance <a class="header-anchor" href="#_4-spin-up-redis-and-postgresql-instance" aria-label="Permalink to “4. Spin up Redis and PostgreSQL instance”">​</a></h4><p>Make sure <code>Redis</code> and <code>PostgreSQL</code> instances are running and accessible.</p><p>To use Docker compose to start the services, run on project root folder:</p><div class="language-sh"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">docker</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> compose</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> up</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -d</span></span></code></pre></div><p>Refer to <a href="./docker">Development using Docker</a> and <a href="./vm">Development using VM</a> sections for options to set up local <code>PostgreSQL</code> and <code>Redis</code> instances.</p><div class="tip custom-block"><p class="custom-block-title custom-block-title-default">TIP</p><p>You may also install <code>PostgreSQL</code> and <code>Redis</code> manually on your local machine. Refer to the official documentation for <a href="https://www.postgresql.org/docs/current" target="_blank" rel="noreferrer">PostgreSQL</a> and <a href="https://redis.io/docs" target="_blank" rel="noreferrer">Redis</a> for installation instructions.</p></div><h4 id="_5-initialise-environment-files" tabindex="-1">5. Initialise environment files <a class="header-anchor" href="#_5-initialise-environment-files" aria-label="Permalink to “5. Initialise environment files”">​</a></h4><p>On project root folder, run below command to build the CLI application under folder using development configuration</p><div class="language-sh"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">pnpm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> cli</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> init:env</span></span></code></pre></div><p>This will create <code>.env</code> files under <code>apps/api</code>, <code>apps/cli</code>, <code>apps/admin</code> and <code>apps/survey</code> folders.</p><p>More details can be found in <a href="/cli/init-env">CLI -&gt; Initialize .env files</a>.</p><p>Edit <code>.env</code> files as required. More details can be found in <a href="/config/">Configuration</a> section.</p><h4 id="_6-populate-system-database" tabindex="-1">6. Populate system database <a class="header-anchor" href="#_6-populate-system-database" aria-label="Permalink to “6. Populate system database”">​</a></h4><p>On project root folder, run below command</p><div class="language-sh"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">pnpm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> cli</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> init:db:system</span></span></code></pre></div><p>This will populate the system database with defaults. Follow the prompts to set up the admin user account.</p><p>More details can be found in <a href="/cli/init-db-system">CLI -&gt; Initialize system database</a>.</p><div class="tip custom-block"><p class="custom-block-title custom-block-title-default">TIP</p><p>The CLI will interactively prompt if you wish to download fresh assets from cloud storage for the initialization process. This is optional if you are using Docker Compose to start database services. You can also specify your own database snapshot files to restore the system database.</p></div><h4 id="_7-run-database-migrations" tabindex="-1">7. Run database migrations <a class="header-anchor" href="#_7-run-database-migrations" aria-label="Permalink to “7. Run database migrations”">​</a></h4><p>Make sure databases are up to date running migration commands under project root folder:</p><div class="language-sh"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">pnpm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> db:migrate</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Shortcut for following commands:</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 1) individual databases migration</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">pnpm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> db:system:migrate</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">pnpm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> db:foods:migrate</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 2) ACL synchronization (after migration and source code updates that may include changes to permissions)</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">pnpm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> acl:sync</span></span></code></pre></div><p>More details can be found in <a href="/guide/database#migrations">Database -&gt; migrations</a>.</p><h4 id="_8-download-extract-food-images" tabindex="-1">8. Download &amp; extract food images <a class="header-anchor" href="#_8-download-extract-food-images" aria-label="Permalink to “8. Download &amp; extract food images”">​</a></h4><p>Run the following command and select to download and extract the images:</p><div class="language-sh"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">pnpm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> cli</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> init:assets</span></span></code></pre></div><p>More details can be found in <a href="/cli/init-assets">CLI -&gt; Download assets</a> and <a href="/guide/database#images">Database -&gt; Images</a> for more instructions.</p><h4 id="_9-start-api-server" tabindex="-1">9. Start API server <a class="header-anchor" href="#_9-start-api-server" aria-label="Permalink to “9. Start API server”">​</a></h4><p>On <code>apps/api</code> folder, run</p><div class="language-sh"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">pnpm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> dev</span></span></code></pre></div><p>The API server should be running on <code>http://localhost:3100</code> by default.</p><h4 id="_10-start-admin-tool-application" tabindex="-1">10. Start admin tool application <a class="header-anchor" href="#_10-start-admin-tool-application" aria-label="Permalink to “10. Start admin tool application”">​</a></h4><p>On <code>apps/admin</code> folder, run</p><div class="language-sh"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">pnpm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> dev</span></span></code></pre></div><p>The Intake24 admin tool application should be running on <code>http://localhost:8100</code> by default, and you can log in using the admin account created during step 5.</p><h4 id="_11-start-frontend-survey-application" tabindex="-1">11. Start frontend (survey) application <a class="header-anchor" href="#_11-start-frontend-survey-application" aria-label="Permalink to “11. Start frontend (survey) application”">​</a></h4><p>On <code>apps/survey</code> folder, run</p><div class="language-sh"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">pnpm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> dev</span></span></code></pre></div><p>The Intake24 frontend (survey) application should be running on <code>http://localhost:8200</code> by default.</p><h2 id="production" tabindex="-1">Production <a class="header-anchor" href="#production" aria-label="Permalink to “Production”">​</a></h2><p>Instead of running applications in development mode, you can build and start them in production mode.</p><p>Build the application</p><div class="language-sh"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">pnpm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> build</span></span></code></pre></div><p>Start the application</p><div class="language-sh"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">pnpm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> start</span></span></code></pre></div><div class="tip custom-block"><p class="custom-block-title">For production, consider environment you plan to use to run the application:</p><ol><li>Deploying as dedicated service. Refer to your OS environment how to set that up.</li><li>Use process manager, e.g. <a href="https://pm2.keymetrics.io" target="_blank" rel="noreferrer">PM2</a></li><li>Deploy behind proper http server, e.g. <a href="https://www.nginx.com" target="_blank" rel="noreferrer">Nginx</a>, <a href="https://www.apache.org" target="_blank" rel="noreferrer">Apache</a> etc.</li></ol></div><p>Deployment section / ansible scripts provide examples how to use dedicated service on Ubuntu and run it behind Nginx reverse proxy.</p>`,67)])])}const g=a(n,[["render",l]]);export{k as __pageData,g as default};
